import styled from 'styled-components';

export const SkillsContainer = styled.section`
background: rgba(80,96,216, .4);
height:100%;
margin:0;

    .title {
        display:block;
        position:absolute;
        top:55em;
        left:40%;
        text-align: center;
        border:1px solid rgba(80,96,216, .4);
        width: 25em;
        height: 3.25em;
        z-index:2;
    }


`
